import React, { useState, useRef } from 'react';
import { Institution, User, Region, SubscriptionPlan, LeadershipMember, AcademicProgram, BlogPost, EventItem, CoreValue, Milestone } from '../types';
import { GoogleGenAI } from "@google/genai";

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const inst = institutions.find(i => i.id === (user.institutionId || institutions.find(i => i.adminId === user.id)?.id));
  const [activeTab, setActiveTab] = useState<'identity' | 'theme' | 'sections' | 'seo' | 'plan' | 'security'>('identity');
  const [activeSectionTab, setActiveSectionTab] = useState<'homepage' | 'about' | 'admissions' | 'academics' | 'news' | 'studentLife' | 'portal'>('homepage');
  const [isGenerating, setIsGenerating] = useState(false);

  const logoInputRef = useRef<HTMLInputElement>(null);
  const coverInputRef = useRef<HTMLInputElement>(null);

  if (!inst) return <div className="p-24 text-center font-black text-slate-300">Portal starting...</div>;

  const handleUpdate = (updatedInst: Institution) => onUpdate(updatedInst);

  const updateSectionField = (section: keyof Institution['sections'], field: string, value: any) => {
    const updatedSections = {
      ...inst.sections,
      [section]: {
        ...inst.sections[section],
        [field]: value
      }
    };
    handleUpdate({ ...inst, sections: updatedSections });
  };

  const updateAdmissionsField = (field: string, value: any) => {
    const updatedAdmissions = {
      ...inst.sections.admissions,
      [field]: value
    };
    updateSectionField('admissions', field, updatedAdmissions[field]);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'logo' | 'cover') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleUpdate({ 
          ...inst, 
          [type === 'logo' ? 'logo' : 'coverImage']: reader.result as string 
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const generateAiCover = async () => {
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `A professional, high-quality landscape photo of a school campus in Eswatini named ${inst.name}, located in the ${inst.region} region. Bright, sunny day, modern educational buildings, lush green surroundings. Cinematic lighting, architectural photography style.`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
      });

      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            const imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            handleUpdate({ ...inst, coverImage: imageUrl });
            break;
          }
        }
      }
    } catch (error) {
      console.error('AI Generation Error:', error);
      // Fallback if AI fails: Use picsum with a seed
      const randomId = Math.floor(Math.random() * 1000);
      handleUpdate({ ...inst, coverImage: `https://picsum.photos/seed/${randomId}/1200/400` });
    } finally {
      setIsGenerating(false);
    }
  };

  const tabs = [
    { id: 'identity', label: 'Identity', icon: '🆔' },
    { id: 'theme', label: 'Appearance', icon: '✨' },
    { id: 'sections', label: 'Site Modules', icon: '🎨' },
    { id: 'seo', label: 'SEO Engine', icon: '📈' },
    { id: 'plan', label: 'Billing', icon: '💳' },
    { id: 'security', label: 'Security', icon: '🔒' }
  ];

  const sectionTabs = [
    { id: 'homepage', label: 'Homepage' },
    { id: 'about', label: 'About' },
    { id: 'admissions', label: 'Admissions' },
    { id: 'academics', label: 'Academics' },
    { id: 'news', label: 'News & Media' },
    { id: 'studentLife', label: 'Student Life' },
    { id: 'portal', label: 'Student Portal' }
  ];

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-8">
         <div className="flex items-center gap-6">
            <div className="w-20 h-20 rounded-3xl shadow-xl border p-2 bg-white flex items-center justify-center overflow-hidden">
               <img src={inst.logo} className="w-full h-full object-contain" />
            </div>
            <div>
               <h1 className="text-4xl font-black text-slate-900 tracking-tight">{inst.name}</h1>
               <div className="flex items-center gap-3 mt-1">
                  <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${inst.plan === SubscriptionPlan.FREE ? 'bg-slate-100' : 'bg-blue-600 text-white'}`}>{inst.plan} Plan</span>
                  <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${inst.status === 'published' ? 'bg-emerald-100 text-emerald-700' : inst.status === 'suspended' ? 'bg-rose-100 text-rose-700' : 'bg-amber-100 text-amber-700'}`}>
                    {inst.status}
                  </span>
               </div>
            </div>
         </div>
         <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border px-6 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-sm">View Site</a>
           <button onClick={() => alert('Changes saved to draft. Publish to go live!')} className="bg-slate-900 text-white px-8 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-2xl">Publish</button>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
         <aside className="lg:col-span-1 space-y-2">
            {tabs.map(t => (
               <button 
                 key={t.id} 
                 onClick={() => setActiveTab(t.id as any)}
                 className={`w-full flex items-center p-5 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all ${activeTab === t.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-100'}`}
               >
                  <span className="text-xl mr-4">{t.icon}</span>
                  {t.label}
               </button>
            ))}
         </aside>

         <div className="lg:col-span-3">
            {activeTab === 'identity' && (
              <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm space-y-12 animate-in fade-in slide-in-from-right-4">
                <section>
                  <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-3">
                    <span className="w-8 h-8 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center text-sm">🏛</span>
                    Core Identity & Status
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Institution Status</label>
                      <select 
                        className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 appearance-none"
                        value={inst.status}
                        onChange={(e) => handleUpdate({ ...inst, status: e.target.value as any })}
                      >
                        <option value="pending">Pending Review</option>
                        <option value="published">Published (Visible to Public)</option>
                        <option value="suspended">Suspended (Private)</option>
                      </select>
                      <p className="mt-2 text-[9px] text-slate-400 font-medium">Changing to 'Published' makes your school visible in the directory immediately.</p>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">School Name</label>
                      <input 
                        className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700" 
                        value={inst.name} 
                        onChange={e => handleUpdate({ ...inst, name: e.target.value })}
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">URL Slug</label>
                      <div className="flex items-center bg-slate-50 rounded-xl px-4">
                        <span className="text-[10px] font-bold text-slate-400 mr-1">/school/</span>
                        <input 
                          className="flex-1 bg-transparent border-none py-3 font-bold text-slate-700" 
                          value={inst.slug} 
                          onChange={e => handleUpdate({ ...inst, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })}
                        />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">MoET Registration No.</label>
                      <input 
                        className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700" 
                        value={inst.moetRegistration} 
                        onChange={e => handleUpdate({ ...inst, moetRegistration: e.target.value })}
                        placeholder="e.g. MoET/HHO/001"
                      />
                    </div>
                  </div>
                </section>

                <section>
                  <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-3">
                    <span className="w-8 h-8 bg-purple-50 text-purple-600 rounded-lg flex items-center justify-center text-sm">🖼</span>
                    Visual Identity
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">School Logo</label>
                      <div className="flex gap-2">
                        <input 
                          className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700" 
                          value={inst.logo} 
                          onChange={e => handleUpdate({ ...inst, logo: e.target.value })}
                          placeholder="Image URL..."
                        />
                        <button 
                          onClick={() => logoInputRef.current?.click()}
                          className="bg-slate-900 text-white px-4 py-3 rounded-xl font-black uppercase tracking-widest text-[8px] whitespace-nowrap"
                        >
                          Select
                        </button>
                        <input 
                          ref={logoInputRef}
                          type="file" 
                          className="hidden" 
                          accept="image/*"
                          onChange={(e) => handleFileChange(e, 'logo')}
                        />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Cover Image</label>
                      <div className="flex gap-2">
                        <input 
                          className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700" 
                          value={inst.coverImage} 
                          onChange={e => handleUpdate({ ...inst, coverImage: e.target.value })}
                          placeholder="Image URL..."
                        />
                        <button 
                          onClick={() => coverInputRef.current?.click()}
                          className="bg-slate-900 text-white px-4 py-3 rounded-xl font-black uppercase tracking-widest text-[8px] whitespace-nowrap"
                        >
                          Select
                        </button>
                        <button 
                          onClick={generateAiCover}
                          disabled={isGenerating}
                          className={`bg-blue-600 text-white px-4 py-3 rounded-xl font-black uppercase tracking-widest text-[8px] whitespace-nowrap ${isGenerating ? 'opacity-50' : 'hover:bg-blue-700'}`}
                        >
                          {isGenerating ? 'Wait...' : 'AI Gen'}
                        </button>
                        <input 
                          ref={coverInputRef}
                          type="file" 
                          className="hidden" 
                          accept="image/*"
                          onChange={(e) => handleFileChange(e, 'cover')}
                        />
                      </div>
                    </div>
                    <div className="md:col-span-2">
                      <p className="text-[9px] text-slate-400 font-medium mb-4 uppercase tracking-widest">Cover Preview</p>
                      <div className="w-full h-48 rounded-2xl overflow-hidden border border-slate-100 bg-slate-50 shadow-inner group relative">
                        <img src={inst.coverImage} className="w-full h-full object-cover" alt="Cover Preview" />
                        {isGenerating && (
                           <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center">
                              <span className="text-white font-black uppercase tracking-[0.2em] text-[10px] animate-pulse">Generating Masterpiece...</span>
                           </div>
                        )}
                        <div className="absolute inset-0 bg-black/0 group-hover:bg-black/5 transition-colors pointer-events-none" />
                      </div>
                    </div>
                  </div>
                </section>

                <section>
                  <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-3">
                    <span className="w-8 h-8 bg-emerald-50 text-emerald-600 rounded-lg flex items-center justify-center text-sm">📍</span>
                    Location & Region
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Region</label>
                      <select 
                        className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 appearance-none"
                        value={inst.region}
                        onChange={(e) => handleUpdate({ ...inst, region: e.target.value as any })}
                      >
                        {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                      </select>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Physical Address</label>
                      <input 
                        className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700" 
                        value={inst.contact.address} 
                        onChange={e => handleUpdate({ ...inst, contact: { ...inst.contact, address: e.target.value } })}
                      />
                    </div>
                  </div>
                </section>
              </div>
            )}

            {activeTab === 'sections' && (
              <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
                <div className="flex bg-white p-2 rounded-2xl shadow-sm border overflow-x-auto whitespace-nowrap scrollbar-hide">
                   {sectionTabs.map(st => (
                     <button key={st.id} onClick={() => setActiveSectionTab(st.id as any)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeSectionTab === st.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>{st.label}</button>
                   ))}
                </div>

                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm min-h-[600px]">
                   {activeSectionTab === 'admissions' && (
                     <div className="space-y-12">
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">1. Admissions Overview</h3>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Headline</label>
                              <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.admissions.headline} onChange={e => updateAdmissionsField('headline', e.target.value)} />
                           </div>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Introduction (150-250 words)</label>
                              <textarea rows={6} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.admissions.introduction} onChange={e => updateAdmissionsField('introduction', e.target.value)} />
                           </div>
                        </section>

                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">2. Entry Requirements</h3>
                           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Academic (Comma Separated)</label>
                                 <textarea rows={3} className="w-full bg-slate-50 border-none rounded-xl px-4 py-3" value={inst.sections.admissions.requirements.academic.join(', ')} onChange={e => updateAdmissionsField('requirements', {...inst.sections.admissions.requirements, academic: e.target.value.split(',').map(v => v.trim())})} />
                              </div>
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Documents (Comma Separated)</label>
                                 <textarea rows={3} className="w-full bg-slate-50 border-none rounded-xl px-4 py-3" value={inst.sections.admissions.requirements.documents.join(', ')} onChange={e => updateAdmissionsField('requirements', {...inst.sections.admissions.requirements, documents: e.target.value.split(',').map(v => v.trim())})} />
                              </div>
                           </div>
                        </section>

                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">3. Application Fees & Processing</h3>
                           <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Fee Amount</label>
                                 <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.admissions.applicationFee.amount} onChange={e => updateAdmissionsField('applicationFee', {...inst.sections.admissions.applicationFee, amount: e.target.value})} />
                              </div>
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Processing Time</label>
                                 <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.admissions.processingTime} onChange={e => updateAdmissionsField('processingTime', e.target.value)} />
                              </div>
                           </div>
                        </section>

                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">4. Tuition & Fee Structure</h3>
                           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Per Term</label>
                                 <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.admissions.tuitionFees.perTerm} onChange={e => updateAdmissionsField('tuitionFees', {...inst.sections.admissions.tuitionFees, perTerm: e.target.value})} />
                              </div>
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Per Year</label>
                                 <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.admissions.tuitionFees.perYear} onChange={e => updateAdmissionsField('tuitionFees', {...inst.sections.admissions.tuitionFees, perYear: e.target.value})} />
                              </div>
                           </div>
                        </section>

                        <section className="space-y-6">
                           <h3 className="text-xl font-black text-slate-900">5. Scholarships</h3>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Scholarship Types (Comma Separated)</label>
                              <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.admissions.scholarships.types.join(', ')} onChange={e => updateAdmissionsField('scholarships', {...inst.sections.admissions.scholarships, types: e.target.value.split(',').map(v => v.trim())})} />
                           </div>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">How to Apply</label>
                              <textarea rows={3} className="w-full bg-slate-50 border-none rounded-xl px-4 py-3" value={inst.sections.admissions.scholarships.howToApply} onChange={e => updateAdmissionsField('scholarships', {...inst.sections.admissions.scholarships, howToApply: e.target.value})} />
                           </div>
                        </section>
                     </div>
                   )}
                </div>
              </div>
            )}
         </div>
      </div>
    </div>
  );
};

export default InstitutionAdminDashboard;

export enum Region {
  HHOHHO = 'Hhohho',
  MANZINI = 'Manzini',
  LUBOMBO = 'Lubombo',
  SHISELWENI = 'Shiselweni'
}

export enum InstitutionType {
  PRIMARY = 'Primary',
  HIGH_SCHOOL = 'High School',
  TERTIARY = 'Tertiary',
  PRIVATE = 'Private',
  PUBLIC = 'Public'
}

export enum SubscriptionPlan {
  FREE = 'Free',
  PREMIUM = 'Premium',
  ENTERPRISE = 'Enterprise'
}

export enum UserRole {
  SUPER_ADMIN = 'Super Admin',
  INSTITUTION_ADMIN = 'Institution Admin',
  VISITOR = 'Visitor'
}

export enum GenderType {
  BOYS = 'Boys',
  GIRLS = 'Girls',
  MIXED = 'Mixed'
}

export interface QuickLink {
  label: string;
  url: string;
}

export interface Announcement {
  id: string;
  title: string;
  date: string;
  content: string;
  isFeatured: boolean;
}

export interface CoreValue {
  name: string;
  description: string;
}

export interface Milestone {
  year: string;
  event: string;
}

export interface LeadershipMember {
  name: string;
  title: string;
  description: string;
  photo?: string;
  qualifications?: string;
  experience?: string;
}

export interface AcademicProgram {
  id: string;
  name: string;
  qualification: string;
  duration: string;
  requirements: string;
  description: string;
  pathways?: string;
}

export interface BlogPost {
  id: string;
  title: string;
  date: string;
  excerpt: string;
  image: string;
}

export interface EventItem {
  id: string;
  title: string;
  date: string;
  location: string;
}

export interface SEOMetadata {
  title: string;
  description: string;
  keywords: string[];
  healthScore: number;
}

export interface AcademicDepartment {
  name: string;
  head: string;
  subjects: string[];
  overview: string;
}

export interface Institution {
  id: string;
  name: string;
  slug: string;
  subdomain?: string;
  logo: string;
  coverImage: string;
  region: Region;
  type: InstitutionType[];
  isVerified: boolean;
  isAccredited: boolean;
  moetRegistration: string;
  isFeatured: boolean;
  trustScore: number;
  plan: SubscriptionPlan;
  status: 'pending' | 'published' | 'suspended';
  seo: SEOMetadata;
  theme: {
    primaryColor: string;
    fontFamily: string;
    borderRadius: string;
    layout: string;
  };
  metadata: {
    gender: GenderType;
    isBoarding: boolean;
    feeRange: { min: number; max: number };
    establishedYear: number;
    studentCount: number;
    hasStudentPortal: boolean;
  };
  contact: {
    address: string;
    phone: string;
    email: string;
    website?: string;
    officeHours: string;
    googleMapsUrl?: string;
    facebook?: string;
    twitter?: string;
    linkedin?: string;
  };
  sections: {
    homepage: {
      heroBanner: string;
      welcomeMessage: string;
      principalMessage: {
        text: string;
        name: string;
        photo?: string;
      };
      quickLinks: QuickLink[];
      announcements: Announcement[];
    };
    about: {
      overview: string;
      history: {
        foundingBackground: string;
        milestones: Milestone[];
        growthSummary: string;
      };
      vision: {
        statement: string;
        explanation: string;
      };
      mission: {
        statement: string;
        description: string;
      };
      coreValues: CoreValue[];
      leadership: {
        principal: LeadershipMember;
        seniorTeam: LeadershipMember[];
      };
      accreditation: {
        registeredWith: string;
        registrationNumber: string;
        examinationBody: string;
        affiliations: string[];
        awards: string[];
      };
      statistics: {
        totalStudents: number;
        totalStaff: number;
        studentTeacherRatio: string;
        yearsOfOperation: number;
        graduationRate: string;
      };
      facilities: {
        overview: string;
        list: string[];
      };
      community: {
        outreach: string;
        partnerships: string;
        socialResponsibility: string;
      };
