        email: string;
        hours: string;
      };
      allowOnlineApplications: boolean;
      onlineApplicationUrl?: string;
      scholarshipApplicationLink?: string;
    };
    academics: {
      overview: {
        headline: string;
        introduction: string;
      };
      curriculum: {
        structure: string;
        examinationBody: string;
        description: string;
      };
      departments: AcademicDepartment[];
      programs: AcademicProgram[];
      calendar: {
        startDate: string;
        terms: { name: string; info: string }[];
        examPeriods: string;
        holidays: string;
        url?: string;
      };
      assessment: {
        approach: string;
        gradingSystem: string;
      };
      support: {
        services: string[];
