import React, { useState, useRef } from 'react';
import { Institution, User, Region, SubscriptionPlan, AcademicDepartment, AcademicProgram } from '../types';
import { GoogleGenAI } from "@google/genai";

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const inst = institutions.find(i => i.id === (user.institutionId || institutions.find(i => i.adminId === user.id)?.id));
  const [activeTab, setActiveTab] = useState<'identity' | 'theme' | 'sections' | 'seo' | 'plan' | 'security'>('identity');
  const [activeSectionTab, setActiveSectionTab] = useState<'homepage' | 'about' | 'admissions' | 'academics' | 'news' | 'studentLife' | 'portal'>('homepage');
  const [academicStep, setAcademicStep] = useState<number>(1);
  const [isGenerating, setIsGenerating] = useState(false);

  const logoInputRef = useRef<HTMLInputElement>(null);
  const coverInputRef = useRef<HTMLInputElement>(null);
  const syllabusInputRef = useRef<HTMLInputElement>(null);
  const [activeProgramIndex, setActiveProgramIndex] = useState<number | null>(null);

  if (!inst) return <div className="p-24 text-center font-black text-slate-300">Portal starting...</div>;

  const handleUpdate = (updatedInst: Institution) => onUpdate(updatedInst);

  const updateSectionField = (section: keyof Institution['sections'], field: string, value: any) => {
    const updatedSections = {
      ...inst.sections,
      [section]: {
        ...inst.sections[section],
        [field]: value
      }
    };
    handleUpdate({ ...inst, sections: updatedSections });
  };

  const updateAcademicField = (field: string, value: any) => {
    const updatedAcademics = {
      ...inst.sections.academics,
      [field]: value
    };
    updateSectionField('academics', field, updatedAcademics[field]);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'logo' | 'cover') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleUpdate({ 
          ...inst, 
          [type === 'logo' ? 'logo' : 'coverImage']: reader.result as string 
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSyllabusUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeProgramIndex !== null) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const newPrograms = [...inst.sections.academics.programs];
        newPrograms[activeProgramIndex].syllabusUrl = reader.result as string;
        updateAcademicField('programs', newPrograms);
        setActiveProgramIndex(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const generateAiCover = async () => {
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `A professional, high-quality landscape photo of a school campus in Eswatini named ${inst.name}, located in the ${inst.region} region. Bright, sunny day, modern educational buildings, lush green surroundings. Cinematic lighting, architectural photography style.`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
      });

      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            const imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            handleUpdate({ ...inst, coverImage: imageUrl });
            break;
          }
        }
      }
    } catch (error) {
      console.error('AI Generation Error:', error);
      const randomId = Math.floor(Math.random() * 1000);
      handleUpdate({ ...inst, coverImage: `https://picsum.photos/seed/${randomId}/1200/400` });
    } finally {
      setIsGenerating(false);
    }
  };

  const tabs = [
    { id: 'identity', label: 'Identity', icon: '🆔' },
    { id: 'theme', label: 'Appearance', icon: '✨' },
    { id: 'sections', label: 'Site Modules', icon: '🎨' },
    { id: 'seo', label: 'SEO Engine', icon: '📈' },
    { id: 'plan', label: 'Billing', icon: '💳' },
    { id: 'security', label: 'Security', icon: '🔒' }
  ];

  const sectionTabs = [
    { id: 'homepage', label: 'Homepage' },
    { id: 'about', label: 'About' },
    { id: 'admissions', label: 'Admissions' },
    { id: 'academics', label: 'Academics' },
    { id: 'news', label: 'News & Media' },
    { id: 'studentLife', label: 'Student Life' },
    { id: 'portal', label: 'Student Portal' }
  ];

  const addDepartment = () => {
    const newDept: AcademicDepartment = { name: '', head: '', subjects: [], overview: '' };
    updateAcademicField('departments', [...inst.sections.academics.departments, newDept]);
  };

  const addProgram = () => {
    const newProg: AcademicProgram = { id: Date.now().toString(), name: '', qualification: '', duration: '', requirements: '', description: '', syllabusUrl: '' };
    updateAcademicField('programs', [...inst.sections.academics.programs, newProg]);
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-8">
         <div className="flex items-center gap-6">
            <div className="w-20 h-20 rounded-3xl shadow-xl border p-2 bg-white flex items-center justify-center overflow-hidden">
               <img src={inst.logo} className="w-full h-full object-contain" />
            </div>
            <div>
               <h1 className="text-4xl font-black text-slate-900 tracking-tight">{inst.name}</h1>
               <div className="flex items-center gap-3 mt-1">
                  <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${inst.plan === SubscriptionPlan.FREE ? 'bg-slate-100' : 'bg-blue-600 text-white'}`}>{inst.plan} Plan</span>
                  <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${inst.status === 'published' ? 'bg-emerald-100 text-emerald-700' : inst.status === 'suspended' ? 'bg-rose-100 text-rose-700' : 'bg-amber-100 text-amber-700'}`}>
                    {inst.status}
                  </span>
               </div>
            </div>
         </div>
         <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border px-6 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-sm">View Site</a>
           <button onClick={() => alert('Changes saved to draft. Publish to go live!')} className="bg-slate-900 text-white px-8 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-2xl">Publish</button>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
         <aside className="lg:col-span-1 space-y-2">
            {tabs.map(t => (
               <button 
                 key={t.id} 
                 onClick={() => setActiveTab(t.id as any)}
                 className={`w-full flex items-center p-5 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all ${activeTab === t.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-100'}`}
               >
                  <span className="text-xl mr-4">{t.icon}</span>
                  {t.label}
               </button>
            ))}
         </aside>

         <div className="lg:col-span-3">
            {activeTab === 'identity' && (
              <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm space-y-12 animate-in fade-in">
                <section>
                  <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-3">
                    <span className="w-8 h-8 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center text-sm">🏛</span>
                    Core Identity & Status
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Institution Status</label>
                      <select 
                        className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 appearance-none"
                        value={inst.status}
                        onChange={(e) => handleUpdate({ ...inst, status: e.target.value as any })}
                      >
                        <option value="pending">Pending Review</option>
                        <option value="published">Published</option>
                        <option value="suspended">Suspended</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">School Name</label>
                      <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.name} onChange={e => handleUpdate({ ...inst, name: e.target.value })} />
                    </div>
                  </div>
                </section>

                <section>
                  <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-3">
                    <span className="w-8 h-8 bg-purple-50 text-purple-600 rounded-lg flex items-center justify-center text-sm">🖼</span>
                    Visual Identity
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">School Logo</label>
                      <div className="flex gap-2">
                        <input className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.logo} onChange={e => handleUpdate({ ...inst, logo: e.target.value })} placeholder="URL..." />
                        <button onClick={() => logoInputRef.current?.click()} className="bg-slate-900 text-white px-4 py-3 rounded-xl font-black uppercase text-[8px]">Select</button>
                        <input ref={logoInputRef} type="file" className="hidden" accept="image/*" onChange={(e) => handleFileChange(e, 'logo')} />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Cover Image</label>
                      <div className="flex gap-2">
                        <input className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.coverImage} onChange={e => handleUpdate({ ...inst, coverImage: e.target.value })} placeholder="URL..." />
                        <button onClick={() => coverInputRef.current?.click()} className="bg-slate-900 text-white px-4 py-3 rounded-xl font-black uppercase text-[8px]">Select</button>
                        <button onClick={generateAiCover} disabled={isGenerating} className="bg-blue-600 text-white px-4 py-3 rounded-xl font-black uppercase text-[8px]">{isGenerating ? '...' : 'AI'}</button>
                        <input ref={coverInputRef} type="file" className="hidden" accept="image/*" onChange={(e) => handleFileChange(e, 'cover')} />
                      </div>
                    </div>
                  </div>
                </section>
              </div>
            )}

            {activeTab === 'sections' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex bg-white p-2 rounded-2xl shadow-sm border overflow-x-auto whitespace-nowrap scrollbar-hide">
                   {sectionTabs.map(st => (
                     <button key={st.id} onClick={() => setActiveSectionTab(st.id as any)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeSectionTab === st.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>{st.label}</button>
                   ))}
                </div>

                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm min-h-[600px]">
                   {activeSectionTab === 'academics' && (
                     <div className="space-y-12">
                        <div className="flex items-center justify-between mb-8 pb-4 border-b">
                          <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Academic Portal Builder</h2>
                          <div className="flex gap-2">
                            {[1, 2, 3, 4, 5, 6].map(step => (
                              <button 
                                key={step} 
                                onClick={() => setAcademicStep(step)} 
                                className={`w-8 h-8 rounded-full text-xs font-black transition-all ${academicStep === step ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-100 text-slate-400'}`}
                              >
                                {step}
                              </button>
                            ))}
                          </div>
                        </div>

                        {academicStep === 1 && (
                          <div className="space-y-8 animate-in slide-in-from-right-4">
                             <h3 className="text-sm font-black text-indigo-600 uppercase tracking-widest">1. Academic Overview</h3>
                             <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Main Academic Headline</label>
                                <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.academics.overview.headline} onChange={e => updateAcademicField('overview', { ...inst.sections.academics.overview, headline: e.target.value })} />
                             </div>
                             <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Academic Introduction</label>
                                <textarea rows={6} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.academics.overview.introduction} onChange={e => updateAcademicField('overview', { ...inst.sections.academics.overview, introduction: e.target.value })} />
                             </div>
                          </div>
                        )}

                        {academicStep === 2 && (
                          <div className="space-y-8 animate-in slide-in-from-right-4">
                             <h3 className="text-sm font-black text-indigo-600 uppercase tracking-widest">2. Curriculum Structure</h3>
                             <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Curriculum Framework</label>
                                <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.academics.curriculum.structure} onChange={e => updateAcademicField('curriculum', { ...inst.sections.academics.curriculum, structure: e.target.value })} placeholder="e.g. Foundation, Intermediate, Senior phases..." />
                             </div>
                             <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Examination Body</label>
