                             Previous
                           </button>
                           {academicStep < 6 ? (
                             <button 
                               onClick={() => setAcademicStep(s => s + 1)}
                               className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] shadow-lg shadow-indigo-100"
                             >
                               Next Step
                             </button>
                           ) : (
                             <button className="bg-emerald-600 text-white px-10 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] shadow-lg shadow-emerald-100">Save Module</button>
                           )}
                        </div>
                     </div>
                   )}
                </div>
              </div>
            )}
         </div>
      </div>
    </div>
  );
};

