const BrowsePage: React.FC<BrowsePageProps> = ({ institutions, region, onSelectRegion, favorites, onToggleFavorite, lang }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedType, setSelectedType] = useState<string>('All');
  const [selectedGender, setSelectedGender] = useState<string>('All');
  const [boardingOnly, setBoardingOnly] = useState(false);

  const filteredInstitutions = useMemo(() => {
    return institutions
      .filter(inst => {
        const matchesRegion = region ? inst.region === region : true;
        const matchesSearch = inst.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                              inst.region.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesType = selectedType === 'All' || inst.type.includes(selectedType as InstitutionType);
        const matchesGender = selectedGender === 'All' || inst.metadata.gender === selectedGender;
        const matchesBoarding = !boardingOnly || inst.metadata.isBoarding;
        return matchesRegion && matchesSearch && matchesType && matchesGender && matchesBoarding && inst.status === 'published';
      })
      .sort((a, b) => (a.isFeatured === b.isFeatured ? 0 : a.isFeatured ? -1 : 1));
  }, [institutions, region, searchTerm, selectedType, selectedGender, boardingOnly]);

  return (
    <div className="min-h-screen bg-slate-50">
      <div className="max-w-7xl mx-auto px-6 lg:px-8 py-12">
        <div className="flex flex-col lg:flex-row gap-12">

          {/* Filters Sidebar */}
          <aside className="lg:w-72 shrink-0 space-y-10">
            <div>
               <h1 className="text-4xl font-black text-slate-900 tracking-tighter mb-2">Explore</h1>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Discovery Engine v2.5</p>
            </div>

            <div className="space-y-8">
               <section className="space-y-4">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Search</label>
                  <div className="relative">
                     <input 
                        type="text"
                        placeholder="School name or city..."
                        className="w-full bg-white border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold shadow-sm focus:ring-2 focus:ring-blue-500 transition-all"
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                     />
                  </div>
               </section>

               <section className="space-y-4">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Region</label>
                  <div className="flex flex-col gap-2">
                     <button onClick={() => onSelectRegion(null)} className={`text-left px-5 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${!region ? 'bg-slate-900 text-white' : 'bg-white border text-slate-500 hover:border-slate-300'}`}>All Regions</button>
                     {Object.values(Region).map(r => (
                        <button key={r} onClick={() => onSelectRegion(r)} className={`text-left px-5 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${region === r ? 'bg-blue-600 text-white shadow-lg' : 'bg-white border text-slate-500 hover:border-slate-300'}`}>{r}</button>
                     ))}
                  </div>
               </section>

               <section className="space-y-4">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Category</label>
                  <select 
                     className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-xs font-bold appearance-none cursor-pointer"
                     value={selectedType}
                     onChange={e => setSelectedType(e.target.value)}
                  >
                     <option value="All">All Types</option>
                     {Object.values(InstitutionType).map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
               </section>

               <section className="space-y-4">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Student Mix</label>
                  <div className="grid grid-cols-2 gap-2">
                     {['All', GenderType.MIXED, GenderType.BOYS, GenderType.GIRLS].map(g => (
                        <button key={g} onClick={() => setSelectedGender(g)} className={`px-3 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest border transition-all ${selectedGender === g ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-400 hover:border-slate-300'}`}>{g}</button>
                     ))}
                  </div>
               </section>

               <section className="flex items-center justify-between p-5 bg-white border rounded-2xl">
                  <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Boarding Facilities</span>
                  <button 
                    onClick={() => setBoardingOnly(!boardingOnly)}
                    className={`w-10 h-6 rounded-full transition-all relative ${boardingOnly ? 'bg-blue-600' : 'bg-slate-200'}`}
                  >
                    <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${boardingOnly ? 'left-5' : 'left-1'}`} />
                  </button>
               </section>
            </div>
          </aside>

          {/* Results Area */}
          <main className="flex-1">
            <div className="flex justify-between items-center mb-10">
               <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{filteredInstitutions.length} Results Found</p>
               <div className="h-px flex-1 mx-8 bg-slate-200 hidden md:block" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-2 gap-8">
               {filteredInstitutions.map(inst => (
                  <div key={inst.id} className="bg-white rounded-[40px] overflow-hidden border border-slate-100 transition-all hover:shadow-2xl flex flex-col group relative">
                     {inst.isFeatured && (
                        <div className="absolute top-6 left-6 z-20 bg-blue-600 text-white px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-[0.15em] shadow-xl flex items-center gap-2">
                           <span className="animate-pulse w-1.5 h-1.5 bg-white rounded-full" />
                           Featured Institution
                        </div>
                     )}

                     <Link to={`/school/${inst.slug}`} className="block relative h-72 overflow-hidden">
                        <img src={inst.coverImage} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" loading="lazy" />
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-900/80 via-transparent to-transparent opacity-60" />
                        <div className="absolute bottom-6 left-6 flex gap-2">
                           {inst.metadata.isBoarding && <span className="px-3 py-1 bg-white/20 backdrop-blur-md rounded-lg text-[8px] font-black text-white uppercase">Boarding</span>}
                           <span className="px-3 py-1 bg-white/20 backdrop-blur-md rounded-lg text-[8px] font-black text-white uppercase">{inst.metadata.gender}</span>
                        </div>
                     </Link>

                     <div className="p-10 flex-grow">
                        <div className="flex justify-between items-start mb-4">
                           <div>
                              <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">{inst.region}</p>
                              <h3 className="text-3xl font-black text-slate-900 group-hover:text-blue-600 transition-colors leading-tight">{inst.name}</h3>
                           </div>
                           <div className="bg-slate-50 p-2 rounded-2xl border shrink-0">
                              <img src={inst.logo} className="w-8 h-8 object-contain" />
                           </div>
                        </div>

                        <div className="flex flex-wrap gap-2 mb-8">
                           {inst.type.map(t => (
                              <span key={t} className="px-3 py-1 bg-slate-100 rounded-lg text-[8px] font-black uppercase text-slate-500">{t}</span>
                           ))}
                        </div>

                        <div className="pt-8 border-t flex items-center justify-between mt-auto">
                           <div className="flex gap-8">
                              <div>
                                 <p className="text-[8px] font-black text-slate-300 uppercase mb-1">Pass Rate</p>
                                 <p className="text-lg font-black text-emerald-500">{inst.sections.academics.performance.passRate}</p>
                              </div>
                              <div>
                                 <p className="text-[8px] font-black text-slate-300 uppercase mb-1">Established</p>
                                 <p className="text-lg font-black text-slate-900">{inst.metadata.establishedYear}</p>
                              </div>
                           </div>
                           <Link 
                              to={`/school/${inst.slug}`} 
                              className="bg-slate-900 text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-blue-600 transition-all shadow-xl shadow-slate-100"
                           >
                              Profile
                           </Link>
                        </div>
                     </div>
                  </div>
               ))}
            </div>

            {filteredInstitutions.length === 0 && (
              <div className="py-32 text-center space-y-6">
                <div className="text-6xl">🔍</div>
                <h3 className="text-2xl font-black text-slate-900">No schools match your search</h3>
                <p className="text-slate-500 max-w-xs mx-auto text-sm font-medium">Try adjusting your filters or search for a different region.</p>
                <button onClick={() => { setSearchTerm(''); onSelectRegion(null); setSelectedType('All'); }} className="text-blue-600 font-black uppercase tracking-widest text-xs">Reset Filters</button>
              </div>
            )}
          </main>
        </div>
      </div>
    </div>
  );
};

export default BrowsePage;

import React, { useState, useRef } from 'react';
import { Institution, User, Region, SubscriptionPlan, AcademicDepartment, AcademicProgram } from '../types';
import { GoogleGenAI } from "@google/genai";

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const inst = institutions.find(i => i.id === (user.institutionId || institutions.find(i => i.adminId === user.id)?.id));
  const [activeTab, setActiveTab] = useState<'identity' | 'theme' | 'sections' | 'seo' | 'plan' | 'security'>('identity');
  const [activeSectionTab, setActiveSectionTab] = useState<'homepage' | 'about' | 'admissions' | 'academics' | 'news' | 'studentLife' | 'portal'>('homepage');
  const [academicStep, setAcademicStep] = useState<number>(1);
  const [isGenerating, setIsGenerating] = useState(false);

  const logoInputRef = useRef<HTMLInputElement>(null);
  const coverInputRef = useRef<HTMLInputElement>(null);
  const syllabusInputRef = useRef<HTMLInputElement>(null);
  const [activeProgramIndex, setActiveProgramIndex] = useState<number | null>(null);

  if (!inst) return <div className="p-24 text-center font-black text-slate-300">Portal starting...</div>;

  const handleUpdate = (updatedInst: Institution) => onUpdate(updatedInst);

  const updateSectionField = (section: keyof Institution['sections'], field: string, value: any) => {
    const updatedSections = {
      ...inst.sections,
      [section]: {
        ...inst.sections[section],
        [field]: value
      }
    };
    handleUpdate({ ...inst, sections: updatedSections });
  };

  const updateAcademicField = (field: string, value: any) => {
    const updatedAcademics = {
      ...inst.sections.academics,
      [field]: value
    };
    updateSectionField('academics', field, updatedAcademics[field]);
  };

  const updateAboutField = (field: string, value: any) => {
    const updatedAbout = {
      ...inst.sections.about,
      [field]: value
    };
    updateSectionField('about', field, updatedAbout[field]);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'logo' | 'cover') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleUpdate({ 
          ...inst, 
          [type === 'logo' ? 'logo' : 'coverImage']: reader.result as string 
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSyllabusUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeProgramIndex !== null) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const newPrograms = [...inst.sections.academics.programs];
        newPrograms[activeProgramIndex].syllabusUrl = reader.result as string;
        updateAcademicField('programs', newPrograms);
        setActiveProgramIndex(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const tabs = [
    { id: 'identity', label: 'Identity', icon: '🆔' },
    { id: 'theme', label: 'Appearance', icon: '✨' },
    { id: 'sections', label: 'Site Modules', icon: '🎨' },
    { id: 'seo', label: 'SEO Engine', icon: '📈' },
    { id: 'plan', label: 'Billing', icon: '💳' },
    { id: 'security', label: 'Security', icon: '🔒' }
  ];

  const sectionTabs = [
    { id: 'homepage', label: 'Homepage' },
    { id: 'about', label: 'About' },
    { id: 'admissions', label: 'Admissions' },
    { id: 'academics', label: 'Academics' },
    { id: 'news', label: 'News & Media' },
    { id: 'studentLife', label: 'Student Life' },
    { id: 'portal', label: 'Student Portal' }
  ];

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-8">
         <div className="flex items-center gap-6">
            <div className="w-20 h-20 rounded-3xl shadow-xl border p-2 bg-white flex items-center justify-center overflow-hidden">
               <img src={inst.logo} className="w-full h-full object-contain" />
            </div>
            <div>
               <h1 className="text-4xl font-black text-slate-900 tracking-tight">{inst.name}</h1>
               <div className="flex items-center gap-3 mt-1">
                  <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${inst.plan === SubscriptionPlan.FREE ? 'bg-slate-100' : 'bg-blue-600 text-white'}`}>{inst.plan} Plan</span>
                  <span className="px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest bg-emerald-100 text-emerald-700">Verified</span>
               </div>
            </div>
         </div>
         <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border px-6 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-sm">View Live Site</a>
           <button className="bg-slate-900 text-white px-8 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-2xl">Publish Changes</button>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
         <aside className="lg:col-span-1 space-y-2">
            {tabs.map(t => (
               <button 
                 key={t.id} 
                 onClick={() => setActiveTab(t.id as any)}
                 className={`w-full flex items-center p-5 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all ${activeTab === t.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-100'}`}
               >
                  <span className="text-xl mr-4">{t.icon}</span>
                  {t.label}
               </button>
            ))}
         </aside>

         <div className="lg:col-span-3">
            {activeTab === 'identity' && (
              <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm space-y-12 animate-in fade-in">
                <section>
                  <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-3">🏛 Registry Details</h3>
