  favorites: string[];
  onToggleFavorite: (id: string) => void;
  compareList: string[];
  onToggleCompare: (id: string) => void;
  lang: 'en' | 'ss';
}

const BrowsePage: React.FC<BrowsePageProps> = ({ 
