import { GoogleGenAI } from "@google/genai";

interface HomePageProps {
  onSelectRegion: (region: Region) => void;
  lang: 'en' | 'ss';
}

const HomePage: React.FC<HomePageProps> = ({ onSelectRegion, lang }) => {
  const navigate = useNavigate();
  const [hoveredRegion, setHoveredRegion] = useState<Region | null>(null);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResult, setAiResult] = useState<string | null>(null);
  const [groundingLinks, setGroundingLinks] = useState<{web: {uri: string, title: string}}[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const handleRegionSelect = (region: Region) => {
    onSelectRegion(region);
    navigate('/browse');
  };

  const handleAiScout = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAiLoading(true);
    setAiResult(null);
    setGroundingLinks([]);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `User query: "${aiQuery}". Use Google Search to find real-time information about schools, athletic news, or Ministry of Education updates in Eswatini related to this query. Summarize your findings and provide helpful advice.`;

      const response = await ai.models.generateContent({ 
        model: 'gemini-3-pro-preview', 
        contents: prompt,
        config: {
          tools: [{googleSearch: {}}]
        }
      });

      setAiResult(response.text);
      if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        const chunks = response.candidates[0].groundingMetadata.groundingChunks as any[];
        setGroundingLinks(chunks.filter(c => c.web).map(c => ({web: c.web})));
      }
    } catch (err) {
      console.error(err);
      setAiResult("I encountered an error connecting to the scout engine. Please try again later.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const content = {
    en: {
      hero: "The Heart of Eswatini Education",
